#include <stdio.h>
#include <string.h>
#define MOD 1000000007
#define M 777

int numDigits(int x){
    int d=0; while(x){ d++; x/=10; } return d?d:1; // x>=1 per constraints
}

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        long long dp[M]; memset(dp,0,sizeof(dp));
        long long add[M];
        int pow10[11]; pow10[0]=1%M; for(int i=1;i<=10;i++) pow10[i]=(pow10[i-1]*10)%M;
        for(int i=0;i<N;i++){
            int a; scanf("%d", &a);
            int d=numDigits(a);
            int aMod=a%M;
            int p=pow10[d];
            memset(add,0,sizeof(add));
            // start new subsequence with only a
            add[aMod] = (add[aMod] + 1) % MOD;
            // extend previous subsequences
            for(int r=0;r<M;r++) if(dp[r]){
                int nr = ( (long long)r * p + aMod ) % M;
                add[nr] = (add[nr] + dp[r]) % MOD;
            }
            // merge
            for(int r=0;r<M;r++) dp[r] = (dp[r] + add[r]) % MOD;
        }
        printf("%lld\n", dp[0]);
    }
    return 0;
}

