import java.io.*;
import java.util.*;

public class Main {
    static final int MOD = 1_000_000_007;
    static final int M = 777;
    static int numDigits(int x){
        int d=0; while(x>0){ d++; x/=10; } return d==0?1:d;
    }
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        int T = fs.nextInt();
        int[] pow10 = new int[11];
        pow10[0] = 1 % M;
        for(int i=1;i<=10;i++) pow10[i] = (pow10[i-1]*10)%M;
        StringBuilder sb = new StringBuilder();
        while(T-- > 0){
            int N = fs.nextInt();
            long[] dp = new long[M];
            long[] add = new long[M];
            for(int i=0;i<N;i++){
                int a = fs.nextInt();
                int d = numDigits(a);
                int aMod = a % M;
                int p = pow10[d];
                Arrays.fill(add, 0);
                add[aMod] = (add[aMod] + 1) % MOD;
                for(int r=0;r<M;r++) if(dp[r]!=0){
                    int nr = (int)(((long)r * p + aMod) % M);
                    add[nr] = (add[nr] + dp[r]) % MOD;
                }
                for(int r=0;r<M;r++) dp[r] = (dp[r] + add[r]) % MOD;
            }
            sb.append(dp[0]).append('\n');
        }
        System.out.print(sb.toString());
    }
    // Fast scanner for large input
    static class FastScanner {
        private final InputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream in){ this.in = in; }
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        int nextInt() throws IOException {
            int c, sign = 1, val = 0;
            do { c = readByte(); } while (c <= ' ');
            if (c == '-') { sign = -1; c = readByte(); }
            while (c > ' ') {
                val = val * 10 + (c - '0');
                c = readByte();
            }
            return val * sign;
        }
    }
}

