import sys
MOD = 1_000_000_007
M = 777

def num_digits(x):
    return len(str(x))

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    pow10 = [1 % M]
    for i in range(1, 11):
        pow10.append((pow10[-1] * 10) % M)
    for _ in range(T):
        N = int(next(it))
        dp = [0] * M
        for _ in range(N):
            a = int(next(it))
            d = num_digits(a)
            a_mod = a % M
            p = pow10[d]
            add = [0] * M
            add[a_mod] = (add[a_mod] + 1) % MOD
            for r, cnt in enumerate(dp):
                if cnt:
                    nr = (r * p + a_mod) % M
                    add[nr] = (add[nr] + cnt) % MOD
            for r in range(M):
                dp[r] = (dp[r] + add[r]) % MOD
        out_lines.append(str(dp[0]))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

